const first = $input.first();
const body = first.json.body || first.json || {};
const binary = first.binary || {};
const now = new Date().toISOString();
const jobId = `ft_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

function parseBoolean(value) {
  return value === true || value === 'true' || value === '1' || value === 1;
}

function normalizeAgeGroup(value) {
  const raw = String(value || '').toLowerCase().trim();
  if (!raw) return '';
  if (/^(child|kid|реб[её]нок|дет[ие]|малыш|мальчик|девочка)$/.test(raw)) return 'child';
  if (/^(teen|teenager|подросток|тинейджер)$/.test(raw)) return 'teen';
  if (/^(adult|взрослый|взрослая|родитель)$/.test(raw)) return 'adult';
  if (/^(senior|elder|пожилой|пожилая|бабушка|дедушка)$/.test(raw)) return 'senior';
  return '';
}

function inferHeroAgeGroup({ explicit, name, description, relation }) {
  const normalizedExplicit = normalizeAgeGroup(explicit);
  if (normalizedExplicit) return { group: normalizedExplicit, source: 'explicit' };

  const text = [name, description, relation].filter(Boolean).join(' ').toLowerCase();
  const ageMatch = text.match(/(?:^|\D)(\d{1,2})\s*(?:лет|год(?:а|ов)?|years?|yo|y\.?o\.?)(?:\D|$)/i);
  if (ageMatch) {
    const age = Number(ageMatch[1]);
    if (age > 0 && age <= 12) return { group: 'child', source: 'age_number' };
    if (age >= 13 && age <= 17) return { group: 'teen', source: 'age_number' };
    if (age >= 60) return { group: 'senior', source: 'age_number' };
    if (age >= 18) return { group: 'adult', source: 'age_number' };
  }

  const keywordRules = [
    { group: 'senior', re: /(бабушк|дедушк|пожил|старик|старушк|grandmother|grandfather|grandma|grandpa|senior|elder)/i },
    { group: 'child', re: /(реб[её]нок|детск|дети|малыш|мальчик|девочка|сын|дочь|дочка|школьник|школьница|ученик|ученица|kid|child|boy|girl)/i },
    { group: 'teen', re: /(подрост|тинейдж|teenager|teen)/i },
    { group: 'adult', re: /(взросл|родител|мама|папа|мать|отец|муж|жена|дядя|т[её]тя|mother|father|parent|adult|uncle|aunt)/i },
  ];
  for (const rule of keywordRules) {
    if (rule.re.test(text)) return { group: rule.group, source: 'keyword' };
  }

  return { group: 'unknown', source: 'not_detected' };
}

const binaryEntries = Object.entries(binary);
const imageBinaryEntries = binaryEntries.filter(([, value]) => String(value?.mimeType || '').startsWith('image/'));

function findPhotoField(n) {
  const exact = `hero${n}_photo`;
  if (binary[exact]) return exact;

  const named = binaryEntries.find(([key, value]) => {
    const fieldName = value?.fieldName || value?.formFieldName || value?.name || '';
    return key === exact || key.startsWith(`${exact}_`) || key.includes(exact) || fieldName === exact || fieldName.includes(exact);
  });
  if (named) return named[0];

  const generic = imageBinaryEntries.filter(([key]) => key === 'data' || /^data\d+$/.test(key) || key.startsWith('data_'));
  return generic[n - 1]?.[0] || null;
}

const heroes = [];
const photoRefs = [];
for (const n of [1, 2, 3, 4]) {
  const photoField = findPhotoField(n);
  const photo = photoField ? binary[photoField] : null;
  const ageInfo = inferHeroAgeGroup({
    explicit: body[`hero${n}_age_group`] || body[`hero${n}_age`] || '',
    name: body[`hero${n}_name`] || '',
    description: body[`hero${n}_desc`] || '',
    relation: body[`hero${n}_rel`] || '',
  });
  const hero = {
    n,
    name: body[`hero${n}_name`] || '',
    description: body[`hero${n}_desc`] || '',
    relation: body[`hero${n}_rel`] || '',
    ageGroup: ageInfo.group,
    ageGroupSource: ageInfo.source,
    photoField,
    photoMime: photo?.mimeType || body[`hero${n}_photo_mime`] || null,
    photoFileName: photo?.fileName || body[`hero${n}_photo_name`] || null,
    hasPhoto: Boolean(photoField),
  };
  if (hero.name || hero.description || hero.photoField) heroes.push(hero);
  if (photoField && photo) {
    const buffer = await this.helpers.getBinaryDataBuffer(0, photoField);
    photoRefs.push({ hero: n, key: photoField, mimeType: hero.photoMime || 'image/jpeg', fileName: hero.photoFileName || null, data: buffer.toString('base64') });
  }
}

return [{
  json: {
    jobId,
    status: 'received',
    createdAt: now,
    source: 'fairyteller_create',
    order: {
      world: body.world || 'disney_light',
      newyearMode: parseBoolean(body.newyear_mode),
      location: body.location || '',
      artifact: body.artifact || '',
      email: String(body.email || '').toLowerCase(),
      illustrationStyle: body.illustration_style || 'photorealistic',
      illustrationStylePrompt: body.illustration_style_prompt || '',
      lengthTarget: Number(body.length_target || 15000),
      chapters: Number(body.chapters || 5),
      titleNeed: parseBoolean(body.title_need),
      language: body.language || 'ru',
      _photoRefs: photoRefs,
      heroes,
    },
    photoRefs,
    pipeline: { next: 'fairyteller_text', previewEnabled: true, portraitizerEnabled: true },
  },
}];

const normalized = $('Normalize Order and Create Job').first().json;
const apiJob = $input.first().json;
return [{
  json: {
    ...normalized,
    jobId: apiJob.jobId || normalized.jobId,
    jobApi: apiJob,
  },
}];
